async function buildMetricoolApprovalEvidenceImportPreview(): Promise<ClipperMetricoolApprovalEvidenceImportSummary> {
  const generatedAt = new Date().toISOString();
  const raw = await readFile(METRICOOL_APPROVAL_EVIDENCE_IMPORT_CSV_PATH, "utf8").catch(() => null);
  const config = await readConfig();
  const accounts = (Array.isArray(config.accounts) && config.accounts.length ? config.accounts : DEFAULT_ACCOUNTS).map(ensureAccountShape);
  return buildMetricoolApprovalEvidenceImportSummaryFromRaw({ raw, accounts, generatedAt }).summary;
}

async function readCachedMetricoolApprovalReportSummary(metricoolApprovalSession: ClipperMetricoolApprovalSessionSummary): Promise<ClipperMetricoolApprovalReportSummary> {
  const raw = await readFile(METRICOOL_APPROVAL_REPORT_PATH, "utf8").catch(() => null);
  if (raw) {
    try {
      const parsed = JSON.parse(raw) as ClipperMetricoolApprovalReportSummary;
      return {
        ...parsed,
        manifestPath: METRICOOL_APPROVAL_REPORT_PATH,
        markdownPath: METRICOOL_APPROVAL_REPORT_MARKDOWN_PATH,
        csvPath: METRICOOL_APPROVAL_REPORT_CSV_PATH,
        approvalSessionPath: METRICOOL_APPROVAL_SESSION_PATH,
        evidenceImportCsvPath: METRICOOL_APPROVAL_EVIDENCE_IMPORT_CSV_PATH,
        importedMetricsPath: METRICOOL_APPROVAL_IMPORTED_METRICS_PATH,
        realPublishEnabled: false,
        approvalRequired: true,
        rows: Array.isArray(parsed.rows) ? parsed.rows : [],
        nextActions: Array.isArray(parsed.nextActions) ? parsed.nextActions : [],
        guardrails: Array.isArray(parsed.guardrails) ? parsed.guardrails : [],
      };
    } catch {
      // Fall through.
    }
  }
  const evidenceImport = await buildMetricoolApprovalEvidenceImportPreview();
  return buildMetricoolApprovalReportSummary({ metricoolApprovalSession, evidenceImport, generatedAt: null });
}

export async function prepareClipperMetricoolApprovalReport(userId = getSystemUserId()): Promise<{ metricoolApprovalReport: ClipperMetricoolApprovalReportSummary; status: ClipperStatus }> {
  await writeDefaultConfigIfMissing();
  await ensureClipperDirs();
  const statusBefore = await getClipperStatus(userId);
  const evidenceImport = await buildMetricoolApprovalEvidenceImportPreview();
  const metricoolApprovalReport = await writeMetricoolApprovalReportArtifacts(buildMetricoolApprovalReportSummary({
    metricoolApprovalSession: statusBefore.metricoolApprovalSession,
    evidenceImport,
    generatedAt: new Date().toISOString(),
  }));
  return { metricoolApprovalReport, status: await getClipperStatus(userId) };
}

export async function importClipperMetricoolApprovalEvidence(userId = getSystemUserId()): Promise<{ metricoolApprovalEvidenceImport: ClipperMetricoolApprovalEvidenceImportSummary; metrics: ClipperMetricsSummary; status: ClipperStatus }> {
  await writeDefaultConfigIfMissing();
  await ensureClipperDirs();
  const generatedAt = new Date().toISOString();
  const raw = await readFile(METRICOOL_APPROVAL_EVIDENCE_IMPORT_CSV_PATH, "utf8").catch(() => null);
  const config = await readConfig();
  const accounts = (Array.isArray(config.accounts) && config.accounts.length ? config.accounts : DEFAULT_ACCOUNTS).map(ensureAccountShape);
  const { summary: metricoolApprovalEvidenceImport, importedMetricRows } = buildMetricoolApprovalEvidenceImportSummaryFromRaw({ raw, accounts, generatedAt });

  if (importedMetricRows.length > 0) {
    await writeFile(METRICOOL_APPROVAL_IMPORTED_METRICS_PATH, renderMetricoolApprovalImportedMetricsCsv(importedMetricRows));
  } else {
    await unlink(METRICOOL_APPROVAL_IMPORTED_METRICS_PATH).catch(() => undefined);
  }

  const metrics = await buildMetricsSummary(accounts);
  await writeFile(METRICS_SUMMARY_PATH, JSON.stringify(metrics, null, 2));

  return { metricoolApprovalEvidenceImport, metrics, status: await getClipperStatus(userId) };
}

export async function recordClipperMetricoolAccountEvidence(userId = getSystemUserId()): Promise<{ metricoolAccountEvidence: ClipperMetricoolAccountEvidenceResult; status: ClipperStatus }> {
  await writeDefaultConfigIfMissing();
  await ensureClipperDirs();
  const config = await readConfig();
  const accounts = (Array.isArray(config.accounts) && config.accounts.length ? config.accounts : DEFAULT_ACCOUNTS).map(ensureAccountShape);
  const metricoolPublishing = await buildClipperMetricoolPublishingSummary(accounts, { syncLiveBrands: true });
  const recorded: ClipperMetricoolAccountEvidenceResult["recorded"] = [];
  const skipped: ClipperMetricoolAccountEvidenceResult["skipped"] = [];

  for (const channel of metricoolPublishing.channels) {
    const account = accounts.find((item) => item.id === channel.accountId);
    if (!account) continue;
    for (const network of channel.connectedNetworks) {
      const platform = metricoolNetworkToClipperPlatform(network);
      if (!platform) {
        skipped.push({ accountId: channel.accountId, accountName: channel.accountName, platform: network, reason: "Network is outside Clippers publishing platforms." });
        continue;
      }
      const platformAccount = account.platformAccounts.find((item) => item.platform === platform);
      if (!platformAccount) {
        skipped.push({ accountId: channel.accountId, accountName: channel.accountName, platform: network, reason: "No matching Clippers platform account." });
        continue;
      }
      const evidencePath = accountEvidenceJsonPath(account.id, platform);
      const profileUrl = profileLinkForPlatform(platform, platformAccount.handle);
      const notes = [
        `Metricool live sync detected ${platform} bridge connection for ${channel.metricoolBrandName} blogId ${channel.metricoolBlogId || "pending"}.`,
        `Expected public profile URL ${profileUrl} and handle ${platformAccount.handle}.`,
        "This is bridge evidence only; it does not verify the external social account until the exact profile/security proof is attached.",
        "Security/2FA is managed in the connected social account and Metricool operator workspace; no secrets stored here.",
        `Proof source: Metricool settings brands sync cached in ${METRICOOL_BRANDS_CACHE_PATH}; capture exact profile proof from Metricool brand connections before marking verified.`,
      ].join(" ");
      await recordClipperAccountEvidence({
        accountId: account.id,
        platform,
        status: "submitted",
        notes,
      }, userId);
      recorded.push({
        accountId: account.id,
        accountName: account.name,
        platform,
        metricoolBrandName: channel.metricoolBrandName,
        metricoolBlogId: channel.metricoolBlogId,
        evidencePath,
      });
    }
  }

  const metricoolAccountEvidence: ClipperMetricoolAccountEvidenceResult = {
    generatedAt: new Date().toISOString(),
    source: "metricool",
    metricoolPublishingStatus: metricoolPublishing.status,
    recorded,
    skipped,
    nextStep: recorded.length > 0
      ? "Refrescar launch kit/readiness y preparar cola Metricool despues de registrar evidencia."
      : "No se detectaron redes Metricool conectadas nuevas para registrar como evidencia.",
  };
  return { metricoolAccountEvidence, status: await getClipperStatus(userId) };
}

export async function prepareClipperPublisherConnectors(userId = getSystemUserId()): Promise<{ publisherConnectors: ClipperPublisherConnectorSummary; status: ClipperStatus }> {
  await writeDefaultConfigIfMissing();
  await ensureClipperDirs();
  const config = await readConfig();
  const oauthConnections = await readOAuthConnections();
  const tokenRecords = await readTokenVaultRecords();
  const accounts = applyOAuthStateToAccounts(
    (Array.isArray(config.accounts) && config.accounts.length ? config.accounts : DEFAULT_ACCOUNTS).map(ensureAccountShape),
    oauthConnections,
    tokenRecords
  );
  const credentialChecks = buildCredentialChecks();
  const permissionPack = await buildPermissionPackSummary();
  const accountEvidence = await buildAccountEvidenceSummary(accounts);
  const accountLaunchKit = await buildAccountLaunchKitSummary(accounts, accountEvidence);
  const developerAppEvidence = await buildDeveloperAppEvidenceSummary();
  const permissionTracker = await buildPermissionTrackerSummary({ accounts, credentialChecks, tokenRecords, oauthConnections, permissionPack, accountLaunchKit });
  const platformReadiness = await buildPlatformReadinessSummary({ credentialChecks, tokenRecords, accountLaunchKit, developerAppEvidence, permissionTracker });
  const productionQueue = await buildProductionQueueSummary(accounts);
  const draftSummary = await buildPublisherConnectorSummary({ tokenRecords, permissionTracker, platformReadiness, productionQueue });
  const publisherConnectors: ClipperPublisherConnectorSummary = {
    ...draftSummary,
    generatedAt: new Date().toISOString(),
    status: draftSummary.totals.ready === draftSummary.totals.platforms && draftSummary.totals.platforms > 0
      ? "ready"
      : draftSummary.totals.ready > 0 || draftSummary.totals.partial > 0
        ? "partial"
        : "blocked",
  };
  await writeFile(PUBLISHER_CONNECTORS_PATH, JSON.stringify(publisherConnectors, null, 2));
  await writeFile(PUBLISHER_CONNECTORS_MARKDOWN_PATH, renderPublisherConnectorMarkdown(publisherConnectors));
  return { publisherConnectors, status: await getClipperStatus(userId) };
}

function buildPublisherExecutionRequestSpec(
  connector: ClipperPublisherConnectorItem | undefined,
  post: ClipperScheduledPost
): ClipperPublisherExecutionQueueItem["requestSpec"] {
  return {
    headers: connector?.payloadFields.some((field) => field.toLowerCase().includes("authorization"))
      ? ["Authorization: Bearer <encrypted token from vault>", "Content-Type: platform-specific"]
      : ["Authorization/access_token: <encrypted token from vault>"],
    payloadFields: connector?.payloadFields || ["platform payload fields unavailable until connector is prepared"],
    mediaSource: post.sourcePath || "<missing source video>",
    tokenSource: connector?.tokenSaved ? "encrypted_vault" : "missing",
  };
}

function buildPublisherExecutionQueueSummary(input: {
  automation: ClipperAutomationSummary;
  publisherConnectors: ClipperPublisherConnectorSummary;
}): ClipperPublisherExecutionQueueSummary {
  const latestRun = input.automation.lastRun;
  const realPublishEnabled = false;
  const items = (latestRun?.posts || []).map<ClipperPublisherExecutionQueueItem>((post) => {
    const connector = input.publisherConnectors.items.find((item) => item.platform === post.platform);
    const approvalRequired = true;
    const gates = [
      {
        id: "post-not-blocked",
        label: "Post sin blocker del automation cycle",
        done: !post.blocker,
        evidence: post.blocker || "Automation cycle no reporto blocker para este post.",
      },
      {
        id: "connector-ready",
        label: "Publisher connector listo",
        done: connector?.status === "ready",
        evidence: connector ? `${connector.label}: ${connector.status}` : "Connector no encontrado.",
      },
      {
        id: "approval-mode",
        label: "Aprobacion humana antes de enviar",
        done: true,
        evidence: "Publisher queue mantiene approval_required; real publish deshabilitado para Clippers.",
      },
      {
        id: "token-source",
        label: "Token cifrado disponible",
        done: Boolean(connector?.tokenSaved),
        evidence: connector?.tokenSaved ? "Token disponible solo desde vault cifrado." : "Token OAuth cifrado no encontrado.",
      },
      {
        id: "source-video",
        label: "Source video adjunto",
        done: Boolean(post.sourcePath),
        evidence: post.sourcePath || "Source video faltante.",
      },
    ];
    const blockers = [
      ...(post.blocker ? [post.blocker] : []),
      ...(connector?.blockers || ["Publisher connector no preparado."]),
    ].filter((blocker, index, all) => blocker && all.indexOf(blocker) === index);
    const canSendNow = false;
    const status: ClipperPublisherExecutionItemStatus = blockers.length > 0
      ? "blocked"
      : canSendNow
        ? "ready_to_send"
        : "queued_for_approval";
    return {
      id: hashId(`${latestRun?.id || "no-run"}-${post.id}-${post.platform}-publisher-execution`),
      postId: post.id,
      queueItemId: post.queueItemId,
      accountId: post.accountId,
      accountName: post.accountName,
      platform: post.platform,
      status,
      approvalRequired,
      canSendNow,
      publishAt: post.publishAt,
      endpoint: connector?.endpoint || "unprepared",
      method: "POST",
      mode: connector?.mode || "direct_post",
      sourcePath: post.sourcePath,
      hook: post.hook,
      captionSeed: post.captionSeed,
      requestSpec: buildPublisherExecutionRequestSpec(connector, post),
      gates,
      blockers,
      nextStep: status === "ready_to_send"
        ? "Real publish habilitado y gates listos; ejecutar adaptador de plataforma."
        : status === "queued_for_approval"
          ? "Revisar y aprobar manualmente antes de habilitar envio real."
          : blockers[0] || "Resolver blockers de publicacion.",
    };
  });
  const totals = items.reduce<ClipperPublisherExecutionQueueSummary["totals"]>((sum, item) => {
    sum.items += 1;
    if (item.status === "blocked") sum.blocked += 1;
    if (item.status === "queued_for_approval") sum.queuedForApproval += 1;
    if (item.status === "ready_to_send") sum.readyToSend += 1;
    if (item.approvalRequired) sum.approvalRequired += 1;
    return sum;
  }, { items: 0, blocked: 0, queuedForApproval: 0, readyToSend: 0, approvalRequired: 0 });
  const status: ClipperPublisherExecutionStatus = !latestRun
    ? "not_prepared"
    : totals.blocked > 0
      ? "blocked"
      : totals.readyToSend > 0 && totals.readyToSend === totals.items
        ? "ready"
        : "approval_required";
  return {
    status,
    generatedAt: null,
    manifestPath: PUBLISHER_EXECUTION_QUEUE_PATH,
    markdownPath: PUBLISHER_EXECUTION_QUEUE_MARKDOWN_PATH,
    csvPath: PUBLISHER_EXECUTION_QUEUE_CSV_PATH,
    sourceAutomationRunId: latestRun?.id || null,
    publishMode: "approval_required",
    realPublishEnabled,
    items,
    totals,
    nextStep: !latestRun
      ? "Correr Automation Cycle para generar posts antes de preparar publisher execution queue."
      : totals.blocked > 0
        ? items.find((item) => item.status === "blocked")?.nextStep || "Resolver blockers antes de enviar."
        : totals.readyToSend > 0
          ? "Queue lista para envio real; mantener monitoreo y evidence capture."
          : "Queue lista para aprobacion humana; no se enviara nada externo hasta aprobar y habilitar real publish.",
  };
}

function renderPublisherExecutionQueueMarkdown(summary: ClipperPublisherExecutionQueueSummary): string {
  return [
    "# Clippers Publisher Execution Queue",
    "",
    `Status: ${summary.status}`,
    `Generated: ${summary.generatedAt || new Date().toISOString()}`,
    `Source automation run: ${summary.sourceAutomationRunId || "none"}`,
    `Publish mode: ${summary.publishMode}`,
    `Real publish enabled: ${summary.realPublishEnabled ? "yes" : "no"}`,
    "",
    "## Totals",
    "",
    `- Items: ${summary.totals.items}`,
    `- Blocked: ${summary.totals.blocked}`,
    `- Queued for approval: ${summary.totals.queuedForApproval}`,
    `- Ready to send: ${summary.totals.readyToSend}`,
    `- Approval required: ${summary.totals.approvalRequired}`,
    "",
    "## Next Step",
    "",
    summary.nextStep,
    "",
    "## Items",
    "",
    ...summary.items.flatMap((item) => [
      `### ${item.accountName} / ${item.platform} / ${item.status}`,
      "",
      `- Post ID: ${item.postId}`,
      `- Publish at: ${item.publishAt}`,
      `- Endpoint: ${item.endpoint}`,
      `- Method: ${item.method}`,
      `- Mode: ${item.mode}`,
      `- Source: ${item.sourcePath || "missing"}`,
      `- Token source: ${item.requestSpec.tokenSource}`,
      `- Approval required: ${item.approvalRequired ? "yes" : "no"}`,
      `- Can send now: ${item.canSendNow ? "yes" : "no"}`,
      `- Next step: ${item.nextStep}`,
      "",
      "Gates:",
      ...item.gates.map((gate) => `- [${gate.done ? "x" : " "}] ${gate.label}: ${gate.evidence}`),
      "",
      item.blockers.length ? "Blockers:" : "Blockers: none",
      ...item.blockers.map((blocker) => `- ${blocker}`),
      "",
      "Request spec:",
      ...item.requestSpec.headers.map((header) => `- Header: ${header}`),
      ...item.requestSpec.payloadFields.map((field) => `- Payload: ${field}`),
      "",
    ]),
  ].join("\n");
}

function renderPublisherExecutionQueueCsv(summary: ClipperPublisherExecutionQueueSummary): string {
  const headers = ["id", "post_id", "account_id", "account_name", "platform", "status", "approval_required", "can_send_now", "publish_at", "endpoint", "mode", "source_path", "token_source", "blockers", "next_step"];
  const rows = summary.items.map((item) => [
    item.id,
    item.postId,
    item.accountId,
    item.accountName,
    item.platform,
    item.status,
    item.approvalRequired ? "yes" : "no",
    item.canSendNow ? "yes" : "no",
    item.publishAt,
    item.endpoint,
    item.mode,
    item.sourcePath || "",
    item.requestSpec.tokenSource,
    item.blockers.join(" | "),
    item.nextStep,
  ]);
  return [headers, ...rows].map((row) => row.map(csvCell).join(",")).join("\n") + "\n";
}

async function readPublisherExecutionQueueSummary(): Promise<ClipperPublisherExecutionQueueSummary> {
  try {
    const raw = await readFile(PUBLISHER_EXECUTION_QUEUE_PATH, "utf8");
    const parsed = JSON.parse(raw) as ClipperPublisherExecutionQueueSummary;
    const items = (Array.isArray(parsed.items) ? parsed.items : []).map((item) => ({
      ...item,
      status: item.status === "ready_to_send" ? "queued_for_approval" : item.status,
      approvalRequired: true,
      canSendNow: false,
    }));
    const totals = items.reduce<ClipperPublisherExecutionQueueSummary["totals"]>((sum, item) => {
      sum.items += 1;
      if (item.status === "blocked") sum.blocked += 1;
      if (item.status === "queued_for_approval") sum.queuedForApproval += 1;
      if (item.approvalRequired) sum.approvalRequired += 1;
      return sum;
    }, { items: 0, blocked: 0, queuedForApproval: 0, readyToSend: 0, approvalRequired: 0 });
    return {
      ...parsed,
      status: parsed.status === "ready" ? "approval_required" : parsed.status || "not_prepared",
      manifestPath: PUBLISHER_EXECUTION_QUEUE_PATH,
      markdownPath: PUBLISHER_EXECUTION_QUEUE_MARKDOWN_PATH,
      csvPath: PUBLISHER_EXECUTION_QUEUE_CSV_PATH,
      publishMode: "approval_required",
      realPublishEnabled: false,
      items,
      totals,
    };
  } catch {
    return {
      status: "not_prepared",
      generatedAt: null,
      manifestPath: PUBLISHER_EXECUTION_QUEUE_PATH,
      markdownPath: PUBLISHER_EXECUTION_QUEUE_MARKDOWN_PATH,
      csvPath: PUBLISHER_EXECUTION_QUEUE_CSV_PATH,
      sourceAutomationRunId: null,
      publishMode: "approval_required",
      realPublishEnabled: false,
      items: [],
      totals: { items: 0, blocked: 0, queuedForApproval: 0, readyToSend: 0, approvalRequired: 0 },
      nextStep: "Correr Automation Cycle para generar posts antes de preparar publisher execution queue.",
    };
  }
}

export async function prepareClipperPublisherExecutionQueue(userId = getSystemUserId()): Promise<{ publisherExecutionQueue: ClipperPublisherExecutionQueueSummary; status: ClipperStatus }> {
  await writeDefaultConfigIfMissing();
  await ensureClipperDirs();
  const statusBefore = await getClipperStatus(userId);
  const draftSummary = buildPublisherExecutionQueueSummary({
    automation: statusBefore.automation,
    publisherConnectors: statusBefore.publisherConnectors,
  });
  const publisherExecutionQueue: ClipperPublisherExecutionQueueSummary = {
    ...draftSummary,
    generatedAt: new Date().toISOString(),
  };
  await writeFile(PUBLISHER_EXECUTION_QUEUE_PATH, JSON.stringify(publisherExecutionQueue, null, 2));
  await writeFile(PUBLISHER_EXECUTION_QUEUE_MARKDOWN_PATH, renderPublisherExecutionQueueMarkdown(publisherExecutionQueue));
  await writeFile(PUBLISHER_EXECUTION_QUEUE_CSV_PATH, renderPublisherExecutionQueueCsv(publisherExecutionQueue));
  return { publisherExecutionQueue, status: await getClipperStatus(userId) };
}

async function buildProductionUrlSetupSummary(): Promise<ClipperProductionUrlSetupSummary> {
  const publicBaseUrl = getPublicBaseUrl();
  const productionUrlReady = isProductionPublicBaseUrl(publicBaseUrl);
  const productionUrlStabilityStatus = productionUrlStability(publicBaseUrl);
  const productionUrlStable = productionUrlStabilityStatus === "stable_public";
  const normalizedBaseUrl = publicBaseUrl.replace(/\/$/, "");
  const productionUrlNote = productionUrlReady
    ? productionUrlStable
      ? "PUBLIC_BASE_URL usa HTTPS estable y no apunta a localhost; apta para registrar redirect URIs y app review."
      : "PUBLIC_BASE_URL usa HTTPS publico pero parece un tunel temporal; sirve para pruebas, no para app review/OAuth final hasta cambiarlo por un dominio/tunel estable."
    : "PUBLIC_BASE_URL debe ser una URL publica HTTPS, no localhost/127.0.0.1, antes de pedir app review o publicar en produccion.";
  const blockers = [
    ...(productionUrlReady ? [] : [productionUrlNote]),
    ...(productionUrlReady && !productionUrlStable ? ["PUBLIC_BASE_URL es un tunel temporal; usa dominio propio, Cloudflare named tunnel, deploy estable o dominio reservado antes de app review/OAuth final."] : []),
  ];
  const platforms: ClipperProductionUrlSetupPlatform[] = PLATFORM_REQUIREMENTS.map((requirement) => ({
    platform: requirement.platform,
    label: requirement.label,
    redirectUri: buildRedirectUri(requirement.platform),
    publicRedirectUri: `${normalizedBaseUrl}/api/clippers/oauth/${requirement.platform}/callback`,
    developerPortalUrl: requirement.developerPortalUrl,
    domainVerificationRequired: requirement.platform === "tiktok",
    publicLegalUrls: [`${normalizedBaseUrl}/clippers/legal/privacy`, `${normalizedBaseUrl}/clippers/legal/terms`],
    publicDemoUrl: `${normalizedBaseUrl}/clippers/review-demo`,
    evidenceRecipeRow: ["developer_app", "", requirement.platform, "submitted", "", "<developer app id/client key/project id>", productionUrlReady ? normalizedBaseUrl : "<public HTTPS base URL>", "<redirect URI + public URL evidence screenshot/proof URL>"].map(csvEscape).join(","),
    checklist: [
      `Registrar redirect URI exacto: ${normalizedBaseUrl}/api/clippers/oauth/${requirement.platform}/callback`,
      `Confirmar que ${normalizedBaseUrl} responde por HTTPS publico.`,
      `Confirmar Privacy URL: ${normalizedBaseUrl}/clippers/legal/privacy`,
      `Confirmar Terms URL: ${normalizedBaseUrl}/clippers/legal/terms`,
      `Confirmar Demo URL: ${normalizedBaseUrl}/clippers/review-demo`,
      requirement.platform === "tiktok"
        ? "Verificar domain/URL prefix para PULL_FROM_URL antes de usar uploads remotos."
        : requirement.platform === "instagram"
          ? "Configurar OAuth redirect URI en Meta App y validar permisos de Instagram Graph API."
          : "Registrar OAuth redirect URI en Google Cloud y completar verificacion/audit si aplica.",
      "Guardar evidencia de configuracion en Developer App Evidence.",
    ],
  }));
  const endpointChecks: ClipperProductionUrlEndpointCheck[] = [
    { id: "app", label: "Clippers app", url: `${normalizedBaseUrl}/clippers`, expected: "HTTP 200 and visible Clippers UI." },
    { id: "privacy", label: "Privacy Policy", url: `${normalizedBaseUrl}/clippers/legal/privacy`, expected: "HTTP 200 and public privacy policy page." },
    { id: "terms", label: "Terms of Service", url: `${normalizedBaseUrl}/clippers/legal/terms`, expected: "HTTP 200 and public terms page." },
    { id: "review-demo", label: "App Review Demo", url: `${normalizedBaseUrl}/clippers/review-demo`, expected: "HTTP 200 and public app review demo page." },
    ...PLATFORM_REQUIREMENTS.map((requirement) => ({
      id: `${requirement.platform}-callback`,
      label: `${requirement.label} OAuth callback`,
      url: `${normalizedBaseUrl}/api/clippers/oauth/${requirement.platform}/callback?preflight=1`,
      expected: "Public route reaches the app in preflight mode without writing OAuth state; platform will call the redirect URI without the preflight query after OAuth.",
    })),
  ];
  const saveChecklist = [
    "Pick a stable HTTPS origin that will not rotate during app review.",
    "Verify /clippers, Privacy, Terms and Review Demo are public before saving.",
    "Save only the origin, for example https://clippers.example.com, without trailing path.",
    "Regenerate Production URL Setup, Legal Policy Pack, Demo Pack and Developer Application Drafts.",
    "Register redirect URIs in TikTok, Meta and Google only after the saved URL is verified.",
  ];
  const setupSession: ClipperProductionUrlSetupSessionItem[] = [
    {
      rank: 1,
      id: "choose-public-url-strategy",
      label: "Choose stable public URL strategy",
      status: productionUrlStable ? "ready" : "blocked",
      owner: "Platform Ops",
      requiredValue: "Cloudflare Tunnel with owned domain, reserved ngrok domain, or stable managed deploy.",
      copyValue: publicBaseUrl,
      clipboardValues: [
        { label: "current_public_base_url", value: publicBaseUrl },
        { label: "recommended_pattern", value: "https://clippers.<owned-domain>" },
      ],
      portalUrl: null,
      verificationUrls: endpointChecks.slice(0, 4).map((check) => check.url),
      evidenceRecipeRow: ["developer_app", "", "tiktok", "draft", "", "<strategy: cloudflare/ngrok/deploy>", productionUrlReady ? normalizedBaseUrl : "<public HTTPS base URL>", "<public URL strategy + owner/operator note>"].map(csvEscape).join(","),
      evidenceNeeded: ["Chosen strategy, public HTTPS URL, and owner/operator note."],
      doneCriteria: ["A stable HTTPS URL is selected and will not rotate during app review/OAuth."],
      nextStep: productionUrlStable
        ? "Stable URL strategy already set."
        : productionUrlReady
          ? "Public quick tunnel works for testing; replace it with Cloudflare named tunnel, reserved domain or managed deploy before app review."
          : "Pick Cloudflare Tunnel, reserved ngrok domain, or managed deploy from HTTPS Tunnel Plan.",
    },
    {
      rank: 2,
      id: "record-public-base-url",
      label: "Record PUBLIC_BASE_URL",
      status: productionUrlReady ? "ready" : "blocked",
      owner: "Credential Ops",
      requiredValue: "A public HTTPS origin without localhost, 127.0.0.1 or .local.",
      copyValue: `PUBLIC_BASE_URL=${publicBaseUrl}`,
      clipboardValues: [
        { label: "env_row", value: `PUBLIC_BASE_URL=${publicBaseUrl}` },
        { label: "example_env_row", value: "PUBLIC_BASE_URL=https://clippers.<owned-domain>" },
      ],
      portalUrl: "/clippers#production-url",
      verificationUrls: endpointChecks.map((check) => check.url),
      evidenceRecipeRow: ["developer_app", "", "youtube", "draft", "", "<PUBLIC_BASE_URL saved>", productionUrlReady ? normalizedBaseUrl : "<public HTTPS base URL>", "<HTTP 200 checks for /clippers privacy terms demo callbacks>"].map(csvEscape).join(","),
      evidenceNeeded: ["Credential Setup/production URL save confirmation.", "HTTP 200 or accessible browser proof for /clippers."],
      doneCriteria: ["PUBLIC_BASE_URL is saved through the Clippers safe store or a valid runtime env var and Production URL Setup reports ready."],
      nextStep: productionUrlReady ? "PUBLIC_BASE_URL saved and valid." : "Paste the final HTTPS origin into PUBLIC_BASE_URL HTTPS and save it through Clippers.",
    },
    ...platforms.map<ClipperProductionUrlSetupSessionItem>((platform, index) => ({
      rank: index + 3,
      id: `register-${platform.platform}-redirect-uri`,
      label: `Register ${platform.label} redirect URI`,
      status: productionUrlReady ? "ready" : "blocked",
      owner: "Permission Ops",
      requiredValue: platform.redirectUri,
      copyValue: platform.redirectUri,
      clipboardValues: [
        { label: "redirect_uri", value: platform.publicRedirectUri },
        { label: "privacy_policy_url", value: platform.publicLegalUrls[0] },
        { label: "terms_url", value: platform.publicLegalUrls[1] },
        { label: "demo_url", value: platform.publicDemoUrl },
      ],
      portalUrl: platform.developerPortalUrl,
      verificationUrls: [platform.publicRedirectUri, ...platform.publicLegalUrls, platform.publicDemoUrl],
      evidenceRecipeRow: platform.evidenceRecipeRow,
      evidenceNeeded: [
        "Screenshot of exact redirect URI saved in developer portal.",
        platform.domainVerificationRequired ? "Domain or URL prefix verification proof." : "OAuth/app settings proof.",
      ],
      doneCriteria: [
        `Developer portal contains exact redirect URI ${platform.redirectUri}.`,
        "Developer App Evidence references this redirect URI and the public base URL.",
      ],
      nextStep: productionUrlReady ? `Register ${platform.redirectUri} in ${platform.developerPortalUrl}.` : "Wait for PUBLIC_BASE_URL public HTTPS, then register this redirect URI.",
    })),
  ];
  const generatedAt = await stat(PRODUCTION_URL_SETUP_PATH).then((file) => file.mtime.toISOString()).catch(() => null);
  return {
    status: !generatedAt ? "not_prepared" : productionUrlStable ? "ready" : productionUrlReady ? "partial" : "blocked",
    generatedAt,
    manifestPath: PRODUCTION_URL_SETUP_PATH,
    markdownPath: PRODUCTION_URL_SETUP_MARKDOWN_PATH,
    publicBaseUrl,
    productionUrlReady,
    productionUrlStable,
    productionUrlStability: productionUrlStabilityStatus,
    productionUrlNote,
    requiredEnvVar: "PUBLIC_BASE_URL",
    requiredProtocol: "https",
    saveChecklist,
    endpointChecks,
    setupSession,
    platforms,
    blockers,
    nextStep: productionUrlReady
      ? productionUrlStable
        ? "Registrar estos redirect URIs en TikTok, Meta y Google; luego correr OAuth Go-Live."
        : "Usar esta URL solo para pruebas; configurar un dominio/tunel estable antes de registrar redirect URIs finales."
      : "Configurar PUBLIC_BASE_URL con una URL publica HTTPS y volver a generar este setup.",
  };
}

